def test_email_verification_complete_flow():
    """
    Complete test of email verification flow.
    Run this in a Streamlit app to test end-to-end.
    """
    import streamlit as st
    from modules.email_manager import EmailVerificationManager
    from modules.persistent_user_manager import PersistentUserManager

    st.title("Email Verification Test Suite")

    # Initialize managers
    user_manager = PersistentUserManager()
    email_manager = EmailVerificationManager(provider="test")

    # Test 1: Request verification
    st.subheader("Test 1: Request Verification")
    test_email = st.text_input("Test email", "test@example.com")

    if st.button("Request Verification"):
        success, message = email_manager.request_verification(
            test_email,
            user_manager.get_user_id()
        )
        st.write(f"Success: {success}")
        st.write(f"Message: {message}")

        # Extract token from message for testing
        if "verify_email=" in message:
            token = message.split("verify_email=")[1]
            st.session_state.test_token = token
            st.info(f"Token saved: {token[:10]}...")

    # Test 2: Verify token
    st.subheader("Test 2: Verify Token")

    if "test_token" in st.session_state:
        token = st.session_state.test_token

        if st.button("Verify Token"):
            success, message, data = email_manager.verify_email(token)

            st.write(f"Success: {success}")
            st.write(f"Message: {message}")

            if data:
                st.json(data)

                # Link email to user
                user_manager.set_verified_email(data["email"])
                st.success("Email linked to user!")

    # Test 3: Check status
    st.subheader("Test 3: Check Verification Status")

    status = email_manager.get_verification_status(user_manager.get_user_id())
    st.json(status)

    # Test 4: User manager integration
    st.subheader("Test 4: User Manager Integration")

    col1, col2, col3 = st.columns(3)

    with col1:
        st.write(f"**Email:** {user_manager.get_email()}")

    with col2:
        st.write(f"**Verified:** {user_manager.is_email_verified()}")

    with col3:
        st.write(f"**Status:** {user_manager.get_email_verification_status()}")


def test_token_security():
    """Test token security features."""
    from modules.email_manager import SecureTokenManager
    import time

    manager = SecureTokenManager()

    # Test 1: Token generation
    token1 = manager.generate_token()
    token2 = manager.generate_token()
    assert token1 != token2, "Tokens should be unique"
    print(f"✅ Token generation: {token1[:10]}...")

    # Test 2: Token hashing
    hash1 = manager.hash_token(token1)
    hash2 = manager.hash_token(token1)
    assert hash1 == hash2, "Same token should produce same hash"
    print(f"✅ Hashing: {hash1[:10]}...")

    # Test 3: Token verification
    assert manager.verify_token(token1, hash1), "Should verify correct token"
    assert not manager.verify_token(token2, hash1), "Should reject wrong token"
    print("✅ Verification: Works correctly")

    # Test 4: Expiration
    now = "2026-01-01T10:00:00"
    assert not manager.is_token_expired(now), "Should not expire in future"
    print("✅ Expiration: Correct behavior")


def test_email_validation():
    """Test email validation."""
    from modules.email_manager import EmailVerificationManager

    manager = EmailVerificationManager(provider="test")

    valid_emails = [
        "test@example.com",
        "user+tag@domain.co.uk",
        "name123@sub.domain.com",
    ]

    invalid_emails = [
        "notanemail",
        "@example.com",
        "user@",
        "user @example.com",
        "",
    ]

    for email in valid_emails:
        assert manager._is_valid_email(email), f"Should accept {email}"
        print(f"✅ Valid: {email}")

    for email in invalid_emails:
        assert not manager._is_valid_email(email), f"Should reject {email}"
        print(f"✅ Rejected: {email}")


