# Pattern 1: Send verification email when user opts in
def send_verification_email_on_opt_in():
    """Example: Send verification when user clicks button."""
    import streamlit as st
    from modules.email_manager import EmailVerificationManager

    email_manager = EmailVerificationManager()

    with st.form("email_form"):
        email = st.text_input("Email")
        submitted = st.form_submit_button("Verify Email")

        if submitted:
            success, message = email_manager.request_verification(
                email,
                user_id="user_123",
                app_url="https://myapp.streamlit.app"
            )

            if success:
                st.success(message)
            else:
                st.error(message)


# Pattern 2: Check verification status on app load
def check_email_verification_on_load():
    """Example: Show verification badge on load."""
    import streamlit as st
    from modules.email_manager import EmailVerificationManager

    email_manager = EmailVerificationManager()
    user_id = st.session_state.user_id

    status = email_manager.get_verification_status(user_id)

    if status["is_verified"]:
        st.success(f"✅ Verified: {status['email']}")
    else:
        st.info("Verify your email to unlock account recovery")


# Pattern 3: Send payment receipt to verified email
def send_payment_receipt():
    """Example: Send receipt after payment."""
    from modules.email_manager import get_payment_receipt_html
    from datetime import datetime

    verified_email = "user@example.com"  # From user_manager
    email_provider = None  # Your email provider instance

    # Generate receipt HTML
    html = get_payment_receipt_html(
        user_email=verified_email,
        payment_id="pay_123",
        amount=2.99,
        payment_type="analysis",
        timestamp=datetime.now().isoformat()
    )

    # Send email
    if email_provider:
        success = email_provider.send_email(
            to_email=verified_email,
            subject="Payment Receipt - Influencer Radar",
            html_content=html
        )


